-- ============================================================
-- AMTR — Demo AFB seed (auto-generated by scripts/extract-amtr-seed.mjs)
-- Loads the standard 1C7X1 catalogs + several sample members with
-- representative progress into the Demo AFB base so every tab and the
-- reports show populated, color-bearing data. Idempotent: re-running
-- clears the base's AMTR rows first. Skips silently if Demo AFB absent.
-- ============================================================

DO $$
DECLARE
  v_base uuid;
  v_m1 uuid; v_m2 uuid; v_m3 uuid; v_m4 uuid; v_m5 uuid;
BEGIN
  SELECT id INTO v_base FROM bases WHERE name = 'Demo AFB' LIMIT 1;
  IF v_base IS NULL THEN
    RAISE NOTICE 'Demo AFB not found; skipping AMTR demo seed';
    RETURN;
  END IF;

  DELETE FROM amtr_members WHERE base_id = v_base;
  DELETE FROM amtr_jqs_catalog WHERE base_id = v_base;
  DELETE FROM amtr_1098_catalog WHERE base_id = v_base;
  DELETE FROM amtr_1098_years WHERE base_id = v_base;
  DELETE FROM amtr_formal_catalog WHERE base_id = v_base;
  DELETE FROM amtr_milestone_catalog WHERE base_id = v_base;
  DELETE FROM amtr_rat_catalog WHERE base_id = v_base;
  DELETE FROM amtr_reference_index WHERE base_id = v_base;

  -- JQS-CFETP catalog (490 rows)

  -- DAF 1098 recurring tasks (23) + years

  -- Formal training courses (29)

  -- RAT courses (13)

  -- QTP/PCG milestones (71)

  -- Master Training Reference Index (governing publications)

  -- ── Sample members (varied skill levels + statuses) ──
    VALUES (v_base, 'Grew, Preston A', 'Amn / E-2', '1C731', 'Demo OSS/OSAA', 'Active', 'A', 'Trainee', '2026-02-01', 'Sunday, Timothy R') RETURNING id INTO v_m1;
    VALUES (v_base, 'Carter, Dana L', 'SrA / E-4', '1C751', 'Demo OSS/OSAA', 'Active', 'R', 'AMOPS', '2024-06-15', 'Sunday, Timothy R') RETURNING id INTO v_m2;
    VALUES (v_base, 'Sunday, Timothy R', 'SSgt / E-5', '1C771', 'Demo OSS/OSAA', 'Active', 'R', 'Trainer/Certifier', '2022-03-01', 'Whitfield, Marcus') RETURNING id INTO v_m3;
    VALUES (v_base, 'Whitfield, Marcus J', 'MSgt / E-7', '1C791', 'Demo OSS/OSAA', 'Active', 'R', 'Airfield Manager', '2020-08-01', NULL) RETURNING id INTO v_m4;
    VALUES (v_base, 'Reyes, Bianca', 'GS-09', '2240', 'Demo OSS/OSAA', 'Civilian', NULL, 'Airfield Automation', '2023-01-10', 'Whitfield, Marcus') RETURNING id INTO v_m5;

  -- Representative 1098 progress (mix of complete / due-soon / overdue)
    SELECT v_base, v_m2, c.id, '2026', DATE '2025-11-30', DATE '2026-11-30', 'DLC' FROM amtr_1098_catalog c WHERE c.base_id=v_base AND c.task='Snow and Ice Control';
    SELECT v_base, v_m1, c.id, '2026', DATE '2025-05-25', DATE '2026-05-25' FROM amtr_1098_catalog c WHERE c.base_id=v_base AND c.task='Airfield Driving';
    SELECT v_base, v_m1, c.id, '2026', DATE '2025-04-01', DATE '2026-04-01' FROM amtr_1098_catalog c WHERE c.base_id=v_base AND c.task='Fire Extinguisher Training';

  -- Representative RAT progress
    SELECT v_base, v_m1, c.id, NULL, DATE '2026-05-28' FROM amtr_rat_catalog c WHERE c.base_id=v_base AND c.course='Active Threat Response';
    SELECT v_base, v_m1, c.id, DATE '2026-01-15', DATE '2027-01-15' FROM amtr_rat_catalog c WHERE c.base_id=v_base AND c.course='Small Arms';
    SELECT v_base, v_m2, c.id, NULL, DATE '2026-05-10' FROM amtr_rat_catalog c WHERE c.base_id=v_base AND c.course='Law of War';

  -- Representative JQS sign-offs (trainee start + certifier complete)
    SELECT v_base, v_m1, c.id, DATE '2026-02-10', DATE '2026-03-01', 'PAG', 'TRS', 'TRS' FROM amtr_jqs_catalog c WHERE c.base_id=v_base AND c.kind='item' AND c.number='1.1';
    SELECT v_base, v_m1, c.id, DATE '2026-03-05', 'PAG' FROM amtr_jqs_catalog c WHERE c.base_id=v_base AND c.kind='item' AND c.number='1.2';

  -- Representative QTP/PCG milestone target windows (5-Level QTP, trainee Grew)
    SELECT v_base, v_m1, c.id, '1-30 Days' FROM amtr_milestone_catalog c WHERE c.base_id=v_base AND c.path='fiveLevelQtp' AND c.topic='Career Progression';
    SELECT v_base, v_m1, c.id, '30-60 Days' FROM amtr_milestone_catalog c WHERE c.base_id=v_base AND c.path='fiveLevelQtp' AND c.topic='Administrative Management';
    SELECT v_base, v_m1, c.id, '60-90 Days' FROM amtr_milestone_catalog c WHERE c.base_id=v_base AND c.path='fiveLevelQtp' AND c.topic='Contingency/Expeditionary Operations';

  RAISE NOTICE 'AMTR demo seed loaded for Demo AFB (base %)', v_base;
END $$;
